// ═══════════════════════════════════════
// DADOS DE TESTE (quando executado manualmente)
// Substitui com dados reais quando usares o webhook
// ═══════════════════════════════════════

return [{
  json: {
    name: 'Fone Bluetooth TWS Pro',
    price: 29.99,
    cost: 8.50,
    currency: 'EUR',
    supplier: 'AliExpress',
    supplier_url: 'https://aliexpress.com/item/exemplo123.html',
    supplier_price: 8.50,
    image_url: 'https://ae01.alicdn.com/kf/example-product.jpg',
    category: 'tecnologia',
    niche: 'gadgets-audio',
    tags: ['bluetooth', 'wireless', 'earbuds', 'trending'],
    trend_score: 85,
    competition_score: 45,
  }
}];

// ═══════════════════════════════════════
// ETAPA 2: Validar e enriquecer dados
// ═══════════════════════════════════════

const input = $input.first().json.body || $input.first().json;

// Validação
if (!input.name) {
  throw new Error('Campo obrigatório em falta: name');
}

// Calcular margem
const price = parseFloat(input.price) || 0;
const cost = parseFloat(input.cost) || parseFloat(input.supplier_price) || 0;
const margin = price > 0 && cost > 0 ? Math.round((price - cost) / price * 100 * 100) / 100 : 0;

// Calcular viability score
const trendScore = parseInt(input.trend_score) || 50;
const competitionScore = parseInt(input.competition_score) || 50;
const marginScore = margin > 60 ? 90 : margin > 40 ? 70 : margin > 20 ? 50 : 30;
const viabilityScore = Math.round((trendScore * 0.4) + ((100 - competitionScore) * 0.3) + (marginScore * 0.3));

const produto = {
  name: input.name,
  description: input.description || '',
  price: price,
  cost: cost,
  margin: margin,
  currency: input.currency || 'EUR',
  supplier: input.supplier || 'desconhecido',
  supplier_url: input.supplier_url || '',
  supplier_price: parseFloat(input.supplier_price) || cost,
  image_url: input.image_url || '',
  category: input.category || 'geral',
  niche: input.niche || '',
  tags: Array.isArray(input.tags) ? input.tags : [],
  trend_score: trendScore,
  competition_score: competitionScore,
  viability_score: viabilityScore,
  pipeline_status: 'novo',
  origin_skill: 'n8n_pipeline',
  metadata: {
    pipeline_started: new Date().toISOString(),
    source: 'webhook'
  }
};

console.log(`✅ Produto validado: ${produto.name} | Margem: ${margin}% | Viabilidade: ${viabilityScore}`);

return [{ json: produto }];

// ═══════════════════════════════════════
// ETAPA 4: Gerar descrição do produto
// (Versão sem API de IA — template inteligente)
// Quando tiveres API Anthropic/OpenAI, substitui por chamada ao LLM
// ═══════════════════════════════════════

const produto = $input.first().json;
// O Supabase retorna array, pegar primeiro item
const p = Array.isArray(produto) ? produto[0] : produto;

const nome = p.name || 'Produto';
const categoria = p.category || 'geral';
const preco = p.price || 0;
const margem = p.margin || 0;
const tags = p.tags ? (typeof p.tags === 'string' ? JSON.parse(p.tags) : p.tags) : [];
const productId = p.id;

// Template de descrição profissional
const descricao = `${nome} — a escolha inteligente para quem procura qualidade e preço justo. `
  + `Na categoria ${categoria}, este produto destaca-se pela sua relação qualidade-preço excecional. `
  + (tags.length > 0 ? `Características: ${tags.join(', ')}. ` : '')
  + `Disponível por apenas €${preco}. Envio rápido e seguro.`;

// Template de título SEO
const tituloSEO = `${nome} | Comprar Online | Melhor Preço ${new Date().getFullYear()}`;

// Template de ad copy
const adCopy = {
  headline: `🔥 ${nome} — Oferta Limitada!`,
  body: `Descobre o ${nome} por apenas €${preco}! ✅ Envio grátis ✅ Qualidade premium ✅ Satisfação garantida`,
  cta: 'Comprar Agora →',
  hashtags: tags.map(t => `#${t.replace(/\s/g, '')}`).join(' '),
};

// Keywords SEO
const seoKeywords = [
  nome.toLowerCase(),
  `comprar ${nome.toLowerCase()}`,
  `${nome.toLowerCase()} preço`,
  `${nome.toLowerCase()} online`,
  categoria.toLowerCase(),
  ...tags.map(t => t.toLowerCase())
];

return [{
  json: {
    product_id: productId,
    generated_title: tituloSEO,
    generated_description: descricao,
    ad_copy: adCopy,
    seo_keywords: seoKeywords,
    pipeline_status: 'descricao_gerada',
  }
}];

// ═══════════════════════════════════════
// ETAPA FINAL: Resumo do pipeline
// ═══════════════════════════════════════

const produtoOriginal = $('2. Validar Produto').first().json;
const descricao = $('4. Gerar Descrição').first().json;

return [{
  json: {
    '🚀 PIPELINE CONCLUÍDO': '════════════════════',
    '📦 Produto': produtoOriginal.name,
    '💰 Preço': `€${produtoOriginal.price}`,
    '📊 Margem': `${produtoOriginal.margin}%`,
    '🎯 Score Viabilidade': `${produtoOriginal.viability_score}/100`,
    '📈 Score Tendência': `${produtoOriginal.trend_score}/100`,
    '🏪 Fornecedor': produtoOriginal.supplier,
    '': '',
    '📝 Título SEO': descricao.generated_title,
    '📄 Descrição': descricao.generated_description.substring(0, 120) + '...',
    '📢 Headline Ad': descricao.ad_copy.headline,
    ' ': '',
    '✅ Status': descricao.pipeline_status,
    '⏰ Processado em': new Date().toLocaleString('pt-PT'),
  }
}];
